function storageKey(){return cloudLabId?`${STORAGE_KEY}:${cloudLabId}`:STORAGE_KEY}function emptyLabState(user){const data=structuredClone(defaultData);data.clients=[];data.services=[];data.prices=[];data.suppliers=[];data.staff=[];data.partners=[];data.checks=[];data.transactions=[];data.categories=[];data.company={...structuredClone(defaultData.company),name:user?.user_metadata?.lab_name||"LabNext",email:user?.email||"",loginUser:"admin",loginPass:"admin"};return data}function loadState(){const saved=localStorage.getItem(STORAGE_KEY);if(!saved)return cleanSeededCategories(structuredClone(defaultData));try{return cleanSeededCategories({...structuredClone(defaultData),...JSON.parse(saved)})}catch{return cleanSeededCategories(structuredClone(defaultData))}}function saveState(){localStorage.setItem(storageKey(),JSON.stringify(state));queueCloudSave()}function bindFinanceTabs(){document.querySelectorAll("[data-finance-tab]").forEach(button=>button.addEventListener("click",()=>{const tab=button.dataset.financeTab;document.querySelectorAll("[data-finance-tab]").forEach(item=>item.classList.toggle("active",item===button));document.querySelectorAll("[data-finance-panel]").forEach(panel=>panel.classList.toggle("active",panel.dataset.financePanel===tab))}))}function bindNavigation(){document.querySelectorAll("[data-view], [data-view-link]").forEach(b=>b.addEventListener("click",()=>showView(b.dataset.view||b.dataset.viewLink)))}function showView(view){document.querySelectorAll(".view").forEach(s=>s.classList.remove("active"));document.querySelector(`#${view}-view`).classList.add("active");document.querySelectorAll(".nav-item").forEach(i=>i.classList.toggle("active",i.dataset.view===view));document.querySelector("#page-title").textContent=document.querySelector(`.nav-item[data-view="${view}"]`)?.textContent||"Gestão";if(view==="subscriptions")renderSubscriptionAdmin()}function bindForms(){document.querySelectorAll("form[data-form]").forEach(form=>form.addEventListener("submit",e=>{e.preventDefault();const c=form.dataset.form;const data=Object.fromEntries(new FormData(form).entries());if(c==="users"){data.username=String(data.username||"").trim();data.name=String(data.name||"").trim();data.role=data.role||"Atendimento";data.status=data.status||"ativo";const duplicate=(state.users||[]).some(user=>user.id!==data.id&&normalizeName(user.username)===normalizeName(data.username));if(duplicate)return alert("Já existe um usuário com esse acesso.")}if(c==="services"){data.items=collectEntryItems(form);if(!data.items.length)return alert("Adicione pelo menos um serviço na nota.");syncLegacyEntryFields(data);data.stage=data.stage||"recebido";if(data.status==="finalizada"){data.exitDate=today;data.stage="finalizado"}if(!data.noteNumber)data.noteNumber=nextNoteNumber()}data.id=data.id||uid();const index=state[c].findIndex(i=>i.id===data.id);index>=0?state[c][index]=data:state[c].push(data);saveState();form.reset();clearEntryItemsForm(form);form.querySelector("[name='id']").value="";setDefaultDates();render()}));document.querySelectorAll("[data-clear-form]").forEach(b=>b.addEventListener("click",()=>{const form=b.closest("form");form.reset();clearEntryItemsForm(form);form.querySelector("[name='id']").value="";setDefaultDates()}))}function bindSearch(){document.querySelectorAll("[data-search]").forEach(input=>input.addEventListener("input",()=>{searchTerms[input.dataset.search]=input.value.toLowerCase();renderTables()}))}function bindImportExport(){document.querySelector("#export-data").addEventListener("click",()=>{const blob=new Blob([JSON.stringify(state,null,2)],{type:"application/json"});const url=URL.createObjectURL(blob);const link=document.createElement("a");link.href=url;link.download=`gestao-lab-${today}.json`;link.click();URL.revokeObjectURL(url)});document.querySelector("#import-data").addEventListener("change",async e=>{const file=e.target.files[0];if(!file)return;state=cleanSeededCategories({...structuredClone(defaultData),...JSON.parse(await file.text())});saveState();e.target.value="";render()})}function render(){populateClientOptions();populateServiceSelect();populateCategoryOptions();populateServiceCatalogOptions();setDefaultDates();ensureEntryItemsForm();populatePaymentEntrySelect();populateBillingClientSelect();populateCommissionStaffSelect();renderClientPayments();renderDashboard();renderFinanceSummary();renderCashBook();renderChecks();renderFinancialExtract();renderBillingReport();renderServicesReport();renderServiceRankingReport();renderClientSpendingReport();renderProfitExpenseReport();renderTables();renderProductionKanban();renderFinalizedProduction();renderEntryTotalSummary();renderCompany();renderSupport()}function populateClientOptions(){const list=document.querySelector("#client-options");if(!list)return;const names=[...new Set((state.clients||[]).map(client=>client.name).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"pt-BR"));list.innerHTML=names.map(name=>`<option value="${esc(name)}"></option>`).join("")}function ensureEntryItemsForm(){const form=document.querySelector('[data-form="services"]');const list=form?.querySelector("#entry-items-list");if(list&&!list.children.length)renderEntryItemRows(form,[{}]);updateEntryTotal(form)}function setDefaultDates(){document.querySelectorAll('input[type="date"]').forEach(i=>{if(i.name==="exitDate"||i.name==="expectedDate")return;if(!i.value)i.value=today})}function populateServiceSelect(){document.querySelectorAll('select[name="serviceId"]').forEach(select=>{const selected=select.value;select.innerHTML='<option value="">Selecione</option>';state.services.forEach(s=>{const o=document.createElement("option");o.value=s.id;o.textContent=s.name;select.append(o)});select.value=selected})}function renderDashboard(){const paid=state.transactions.filter(i=>i.status==="pago");const income=sum(paid.filter(i=>i.type==="entrada"));const outcome=sum(paid.filter(i=>(i.type==="saida"||i.type==="saída")));document.querySelector("#metrics").innerHTML=[metric("Clientes",state.clients.length),metric("Entradas",state.services.length),metric("Total pedidos",money(sumEntryOrders())),metric("Saldo pago",money(income-outcome)),metric("Pendentes",money(sum(state.transactions.filter(i=>i.status==="pendente"))))].join("");renderRecentTransactions();renderPricePreview()}function metric(label,value){return`<article class="metric"><span>${label}</span><strong>${value}</strong></article>`}function renderRecentTransactions(){const c=document.querySelector("#recent-transactions");const items=[...state.transactions].sort((a,b)=>String(b.date).localeCompare(String(a.date))).slice(0,5);c.innerHTML=items.length?items.map(i=>`<article class="list-item"><div><strong>${esc(i.description)}</strong><span>${formatDate(i.date)} - ${i.type==="saida"||i.type==="saída"?"Saída":"Entrada"}</span></div><strong class="${i.type==="entrada"?"amount-in":"amount-out"}">${money(i.amount)}</strong></article>`).join(""):emptyState()}function renderPricePreview(){const c=document.querySelector("#price-preview");const items=state.prices.slice(0,5);c.innerHTML=items.length?items.map(i=>`<article class="list-item"><div><strong>${esc(priceServiceName(i))}</strong><span>Custo: ${money(i.cost)} | Margem: ${money((Number(i.salePrice)||0)-(Number(i.cost)||0))}</span></div><strong>${money(i.salePrice)}</strong></article>`).join(""):emptyState()}function renderFinanceSummary(){const paid=state.transactions.filter(i=>i.status==="pago");const income=sum(paid.filter(i=>i.type==="entrada"));const outcome=sum(paid.filter(i=>(i.type==="saida"||i.type==="saída")));const pending=sum(state.transactions.filter(i=>i.status==="pendente"));document.querySelector("#finance-summary").innerHTML=[pill("Entradas pagas",money(income),"amount-in"),pill("Saídas pagas",money(outcome),"amount-out"),pill("Saldo",money(income-outcome),income-outcome>=0?"amount-in":"amount-out"),pill("Pendentes",money(pending),"")].join("")}function pill(label,value,cls){return`<div class="summary-pill"><span>${label}</span><strong class="${cls}">${value}</strong></div>`}function renderTables(){Object.keys(schemas).forEach(c=>{const table=document.querySelector(`[data-table="${c}"]`);if(!table)return;const schema=schemas[c];const rows=filteredRows(c);table.innerHTML=`<thead><tr>${schema.columns.map(([,l])=>`<th>${l}</th>`).join("")}<th>Ações</th></tr></thead><tbody>${rows.length?rows.map(i=>renderRow(c,i)).join(""):`<tr><td colspan="${schema.columns.length+1}">${emptyState()}</td></tr>`}</tbody>`})}function filteredRows(c){const term=searchTerms[c];if(!term)return state[c];return state[c].filter(i=>Object.values(i).some(v=>String(v).toLowerCase().includes(term)))}function daysUntil(date){if(!date)return null;const due=new Date(`${date}T00:00:00`);const now=new Date(`${today}T00:00:00`);if(Number.isNaN(due.getTime()))return null;return Math.ceil((due-now)/86400000)}function entryDueClass(entry){if(!entry||entry.status==="finalizada")return"";const days=daysUntil(entry.expectedDate);if(days===null)return"";if(days<=1)return"entry-due-1";if(days<=3)return"entry-due-3";return""}function entryDueLabel(entry){if(!entry||entry.status==="finalizada")return"";const days=daysUntil(entry.expectedDate);if(days===null||days>3)return"";if(days<0)return"Atrasada";if(days===0)return"Vence hoje";if(days===1)return"Vence em 1 dia";return`Vence em ${days} dias`}function renderRow(c,item){const schema=schemas[c];const rowClass=c==="services"?entryDueClass(item):"";const cells=schema.columns.map(([key])=>{const f=schema.format?.[key];const raw=key==="margin"?"":item[key];return`<td>${f?f(raw,item):esc(raw||"")}</td>`}).join("");return`<tr class="${rowClass}">${cells}<td><div class="row-actions"><button class="icon-button" title="Editar" onclick="editItem('${c}','${item.id}')">E</button>${c==="services"?`<button class="icon-button" title="Visualizar nota" onclick="viewEntryNote('${item.id}')">V</button>`:""}${c==="services"&&item.status!=="finalizada"?`<button class="icon-button" title="Finalizar" onclick="finalizeEntry('${item.id}')">F</button>`:""}<button class="icon-button danger" title="Excluir" onclick="deleteItem('${c}','${item.id}')">Excluir</button></div></td></tr>`}function editItem(c,id){const item=state[c].find(e=>e.id===id);const form=document.querySelector(`[data-form="${c}"]`);if(!item||!form)return;Object.entries(item).forEach(([k,v])=>{if(form.elements[k])form.elements[k].value=v});if(c==="services")populateEntryItemsForm(form,item);showView({transactions:"finance",clients:"clients",services:"services",prices:"prices",suppliers:"suppliers",staff:"staff",partners:"partners",users:"users"}[c]);if(c==="transactions")showFinanceTab("cashbook");form.scrollIntoView({behavior:"smooth",block:"start"})}function deleteItem(c,id){const item=state[c]?.find(entry=>entry.id===id);const label=c==="services"?`a entrada de ${item?.patient||item?.name||"produção"}`:"este registro";const message=c==="services"?`Deseja excluir ${label}? O valor ${money(entryTotalAmount(item))} será removido dos totais. Esta ação não pode ser desfeita.`:`Deseja excluir ${label}? Esta ação não pode ser desfeita.`;if(!confirm(message))return;state[c]=state[c].filter(i=>i.id!==id);saveState();render()}function sum(items){return items.reduce((t,i)=>t+(Number(i.amount)||0),0)}function money(v){return currency.format(Number(v)||0)}function serviceName(id){return state.services.find(s=>s.id===id)?.name||"Entrada não encontrada"}function formatDate(v){return v?v.split("-").reverse().join("/"):""}function emptyState(){return document.querySelector("#empty-state").innerHTML}function esc(v){return String(v).replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#039;")}
function bindDentistReport(){const generate=document.querySelector("#generate-dentist-report");const print=document.querySelector("#print-dentist-report");if(generate)generate.addEventListener("click",renderDentistReport);if(print)print.addEventListener("click",()=>{renderDentistReport();window.print()})}
function renderDentistReport(){const box=document.querySelector("#dentist-report");if(!box)return;const dentists=[...state.clients].sort((a,b)=>String(a.name||"").localeCompare(String(b.name||""),"pt-BR"));if(!dentists.length){box.innerHTML=emptyState();return}box.innerHTML=`<div class="report-heading"><strong>Relatório de clientes cadastrados</strong><span>Total: ${dentists.length}</span></div><ol class="report-list">${dentists.map(d=>`<li><strong>${esc(d.name||"")}</strong><span>CRO: ${esc(d.cro||"Não informado")}</span><span>Telefone: ${esc(d.phone||"Não informado")}</span><span>E-mail: ${esc(d.email||"Não informado")}</span><span>Endereço: ${esc(d.address||"Não informado")}</span><span>Cidade: ${esc(d.city||"Não informado")}</span></li>`).join("")}</ol>`}

function bindCategoryRegistration(){document.addEventListener("click",event=>{const button=event.target.closest("#add-category, [data-add-category]");if(!button)return;const formName=button.dataset.addCategory||"services";const field=document.querySelector(`[data-form="${formName}"] [name="category"]`);const typed=(field?.value||"").trim();const name=typed||prompt("Digite o nome do novo setor:");const category=String(name||"").trim();if(!category)return;state.categories=state.categories||[];if(!state.categories.some(item=>item.toLowerCase()===category.toLowerCase())){state.categories.push(category);state.categories.sort((a,b)=>a.localeCompare(b,"pt-BR"));saveState()}if(field)field.value=category;populateCategoryOptions();populateServiceCatalogOptions()})}
function populateCategoryOptions(){const list=document.querySelector("#category-options");if(!list)return;state.categories=cleanSeededCategories(state).categories||[];const categories=[...new Set(state.categories.filter(Boolean))].sort((a,b)=>a.localeCompare(b,"pt-BR"));state.categories=categories;list.innerHTML=categories.map(category=>`<option value="${esc(category)}"></option>`).join("")}

function priceServiceName(item){return item.name||serviceName(item.serviceId)}
function populateServiceCatalogOptions(){const serviceList=document.querySelector("#service-options");const priceCategoryList=document.querySelector("#price-category-options");const services=[...new Set((state.prices||[]).map(item=>item.name||serviceName(item.serviceId)).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"pt-BR"));if(serviceList)serviceList.innerHTML=services.map(name=>`<option value="${esc(name)}"></option>`).join("");if(priceCategoryList){state.categories=cleanSeededCategories(state).categories||[];const categories=[...new Set((state.categories||[]).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"pt-BR"));priceCategoryList.innerHTML=categories.map(name=>`<option value="${esc(name)}"></option>`).join("")}}function serviceCatalogItem(name){const selected=String(name||"").trim().toLowerCase();return (state.prices||[]).find(price=>String(price.name||serviceName(price.serviceId)).trim().toLowerCase()===selected)}function serviceSector(name){return serviceCatalogItem(name)?.category||""}
function bindServicePriceFill(){document.addEventListener("change",event=>{if(!event.target.matches('[data-form="services"] [name="service"], [data-form="services"] [name="itemService"]'))return;const selected=String(event.target.value||"").trim().toLowerCase();const item=serviceCatalogItem(selected);if(!item)return;const row=event.target.closest(".entry-item-row");const form=event.target.closest("form");if(row){const value=row.querySelector('[name="itemValue"]');const category=row.querySelector('[name="itemCategory"]');if(value&&!value.value)value.value=item.salePrice||"";if(category)category.value=item.category||"";updateEntryTotal(form);return}if(form?.elements.value&&!form.elements.value.value)form.elements.value.value=item.salePrice||"";updateEntryTotal(form)})}

function normalizeEntryItem(item){return{category:item?.category||"",service:item?.service||"",quantity:item?.quantity||"",value:item?.value||"",discount:item?.discount||"",color:item?.color||"",odontogram:item?.odontogram||""}}
function entryItems(entry){const stored=Array.isArray(entry?.items)?entry.items.map(normalizeEntryItem).filter(item=>item.service||item.category||Number(item.quantity)||Number(item.value)||Number(item.discount)||item.color||item.odontogram):[];if(stored.length)return stored;const legacy=normalizeEntryItem(entry||{});return legacy.service||legacy.category||Number(legacy.quantity)||Number(legacy.value)||Number(legacy.discount)||legacy.color||legacy.odontogram?[legacy]:[]}
function entryItemTotal(item){const quantity=Number(item.quantity)||0;const value=Number(item.value)||0;const discount=Number(item.discount)||0;return Math.max(0,quantity*value-discount)}
function entryQuantity(entry){return entryItems(entry).reduce((total,item)=>total+(Number(item.quantity)||0),0)}
function entryServiceLabel(entry){const items=entryItems(entry);if(!items.length)return "";const first=items[0].service||"Serviço";return items.length>1?first+" + "+(items.length-1):first}
function syncLegacyEntryFields(entry){const first=entryItems(entry)[0]||{};["category","service","quantity","value","discount","color","odontogram"].forEach(key=>entry[key]=first[key]||"");entry.total=calculateEntryTotal(entry);return entry}
function collectEntryItems(form){const items=[];form.querySelectorAll(".entry-item-row").forEach(row=>{const item={category:row.querySelector("[name=itemCategory]")?.value||serviceSector(row.querySelector("[name=itemService]")?.value),service:row.querySelector("[name=itemService]")?.value||"",quantity:row.querySelector("[name=itemQuantity]")?.value||"",value:row.querySelector("[name=itemValue]")?.value||"",discount:row.querySelector("[name=itemDiscount]")?.value||"",color:row.querySelector("[name=itemColor]")?.value||"",odontogram:row.querySelector("[name=itemOdontogram]")?.value||""};if(item.service||Number(item.quantity)||Number(item.value)||Number(item.discount)||item.color||item.odontogram)items.push(normalizeEntryItem(item))});return items}
function entryItemRowMarkup(item={}){item=normalizeEntryItem(item);return "<div class=\"entry-item-row\"><input type=\"hidden\" name=\"itemCategory\" value=\""+esc(item.category)+"\" /><input name=\"itemService\" list=\"service-options\" placeholder=\"Serviço\" value=\""+esc(item.service)+"\" /><input name=\"itemQuantity\" type=\"number\" min=\"1\" step=\"1\" placeholder=\"Qtd.\" value=\""+esc(item.quantity)+"\" /><input name=\"itemValue\" type=\"number\" min=\"0\" step=\"0.01\" placeholder=\"Valor\" value=\""+esc(item.value)+"\" /><input name=\"itemDiscount\" type=\"number\" min=\"0\" step=\"0.01\" placeholder=\"Desc.\" value=\""+esc(item.discount)+"\" /><input name=\"itemColor\" placeholder=\"Cor\" value=\""+esc(item.color)+"\" /><input name=\"itemOdontogram\" placeholder=\"Dentes\" value=\""+esc(item.odontogram)+"\" /><button type=\"button\" class=\"danger\" data-remove-entry-item>Excluir</button></div>"}
function renderEntryItemRows(form,items=[]){const list=form?.querySelector("#entry-items-list");if(list)list.innerHTML=items.map(entryItemRowMarkup).join("")}
function clearEntryItemsForm(form){renderEntryItemRows(form,[{}]);updateEntryTotal(form)}
function populateEntryItemsForm(form,entry){const items=entryItems(entry);renderEntryItemRows(form,items.length?items:[{}]);updateEntryTotal(form)}
function addEntryItemFromForm(form){if(!form)return;const list=form.querySelector("#entry-items-list");if(list)list.insertAdjacentHTML("beforeend",entryItemRowMarkup({}));updateEntryTotal(form)}
function entryServiceRows(entry){return entryItems(entry).map(item=>({entry,...item,total:entryItemTotal(item)}))}
function calculateEntryTotal(entry){return entryItems(entry).reduce((total,item)=>total+entryItemTotal(item),0).toFixed(2)}
function bindEntryTotalCalculation(){document.addEventListener("input",event=>{const form=event.target.closest('[data-form="services"]');if(!form)return;updateEntryTotal(form)});document.addEventListener("change",event=>{const form=event.target.closest('[data-form="services"]');if(form)updateEntryTotal(form)});document.addEventListener("click",event=>{const add=event.target.closest("#add-entry-service");if(add){addEntryItemFromForm(add.closest("form"));return}const remove=event.target.closest("[data-remove-entry-item]");if(remove){const form=remove.closest("form");remove.closest(".entry-item-row")?.remove();updateEntryTotal(form)}})}
function updateEntryTotal(form){if(!form||!form.elements.total)return;const entry={items:collectEntryItems(form)};form.elements.total.value=calculateEntryTotal(entry)}
function finalizeEntry(id){const item=state.services.find(entry=>entry.id===id);if(!item)return;if(!item.noteNumber)item.noteNumber=nextNoteNumber();item.status="finalizada";item.stage="finalizado";item.exitDate=today;item.total=calculateEntryTotal(item);saveState();render()}

function bindNoteViewer(){const close=document.querySelector("#close-note");const print=document.querySelector("#print-note");if(close)close.addEventListener("click",closeEntryNote);if(print)print.addEventListener("click",printEntryNote);document.addEventListener("keydown",event=>{if(event.key==="Escape")closeEntryNote()})}
function viewEntryNote(id){const entry=state.services.find(item=>item.id===id);const modal=document.querySelector("#note-modal");const content=document.querySelector("#note-content");if(!entry||!modal||!content)return;if(!entry.noteNumber){entry.noteNumber=nextNoteNumber();saveState()}entry.total=calculateEntryTotal(entry);document.querySelector(".note-toolbar h2").textContent="Nota da entrada";content.innerHTML=renderEntryNote(entry);modal.hidden=false}
function closeEntryNote(){const modal=document.querySelector("#note-modal");if(modal)modal.hidden=true;document.body.classList.remove("printing-note")}function printEntryNote(){document.body.classList.add("printing-note");window.print();setTimeout(()=>document.body.classList.remove("printing-note"),500)}
function renderEntryNote(entry){const status=entry.status||"aberta";const isFinalized=status==="finalizada";const issuedAt=new Date().toLocaleString("pt-BR",{dateStyle:"short",timeStyle:"short"});const noteNumber=entry.noteNumber||"";const datePanel=isFinalized?`<p><span>Finalizado:</span><strong>${formatDate(entry.exitDate)||"-"}</strong></p>`:`<p><span>Entrada:</span><strong>${formatDate(entry.entryDate)||"-"}</strong></p><p><span>Prevista:</span><strong>${formatDate(entry.expectedDate)||"-"}</strong></p>`;const items=entryItems(entry);const total=calculateEntryTotal(entry);const rows=items.length?items.map(item=>`<tr><td>${esc(item.quantity||"0")}</td><td>${esc(item.odontogram||"-")}</td><td><strong>${esc(item.service||"")}</strong><small>${esc(item.category||"")}</small></td><td>${money(item.value)}</td><td>${money(item.discount)}</td><td><strong>${money(entryItemTotal(item))}</strong></td></tr>`).join(""):`<tr><td colspan="6">${emptyState()}</td></tr>`;return `<section class="note-paper os-note modern-document">${documentHeaderMarkup("Nota de Entrada",noteNumber?`Nota ${noteNumber}`:"Ordem de serviço",`<span>Emitida em ${esc(issuedAt)}</span><div class="os-barcode" aria-hidden="true"></div>`)}<section class="os-client-box"><div><p><span>Cliente:</span><strong>${esc(entry.name||"")}</strong></p><p><span>Paciente:</span><strong>${esc(entry.patient||"")}</strong></p><p><span>Ficha:</span><strong>${esc(noteNumber)}</strong></p><p><span>Endereço:</span><strong>-</strong></p></div><div><p><span>Emissão:</span><strong>${esc(issuedAt)}</strong></p>${datePanel}<p><span>Status:</span><strong>${esc(status)}</strong></p></div></section><table class="os-table"><thead><tr><th>Qtd.</th><th>Dentes</th><th>Descrição (Serviços)</th><th>Unitário</th><th>%</th><th>Total</th></tr></thead><tbody>${rows}</tbody></table><div class="os-subtotal"><strong>Subtotal ${money(total)}</strong></div><section class="os-body"><div class="os-tech"><p><span>Escala:</span><strong>-</strong></p><p><span>Cor:</span><strong>${esc(items.map(item=>item.color).filter(Boolean).join(", ")||"-")}</strong></p><p><span>Antagonista:</span><strong>-</strong></p><p><span>Modelo:</span><strong>-</strong></p><p><span>Setor:</span><strong>${esc(items.map(item=>item.category).filter(Boolean).join(", ")||"-")}</strong></p><p><span>Mat. Devol.:</span><strong>-</strong></p><p><span>Caixa:</span><strong>-</strong></p><p><span>Cod:</span><strong>${esc(noteNumber)}</strong></p><p><span>OBS:</span><strong>${esc(entry.description||"Sem observações.")}</strong></p></div><div class="os-payment"><div class="os-total-card">Total Pedido: ${money(total)}</div><p><span>Saldo anterior:</span><strong>R$ 0,00</strong></p><p><span>Saldo atual:</span><strong>${money(total)}</strong></p><p><span>Informativo do último pagamento:</span><strong>R$ 0,00</strong></p><div class="os-signature"><span>________________________________________</span><small>Recebi o(s) trabalho(s) acima</small></div></div></section></section>`}function labNextLogoMarkup(extraClass=""){const initials=companyInitials();return `<div class="labnext-logo ${esc(extraClass)}"><div class="labnext-logo-symbol"><b>${esc(initials)}</b><i></i></div><small>Laboratório</small></div>`}function documentHeaderMarkup(title,subtitle="",extra=""){const company=companyData();return `<header class="document-header"><div class="document-logo-wrap">${labNextLogoMarkup()}</div><div class="document-company"><strong>${esc(company.name||"LabNext")}</strong><span>${esc(company.email||"")}</span><span>${esc(company.phone||"")}</span><span>${esc(company.address||"")}</span></div><div class="document-meta"><strong>${esc(title)}</strong>${subtitle?`<span>${esc(subtitle)}</span>`:""}${extra}</div></header>`}function nextNoteNumber(){const numbers=(state.services||[]).map(item=>Number(item.noteNumber)||0);const next=Math.max(0,...numbers)+1;return String(next).padStart(6,"0")}




const productionStages=[{id:"recebido",label:"Recebido"},{id:"cadcam",label:"Cad-Cam"},{id:"producao",label:"Produção"},{id:"conferencia",label:"Conferência"},{id:"finalizado",label:"Finalizado"}];
function normalizeStage(value){return value==="produção"?"producao":value==="conferência"?"conferencia":value==="acabamento"?"producao":value==="cad-cam"?"cadcam":value}function stageLabel(value){const stage=productionStages.find(item=>item.id===normalizeStage(value));return stage?stage.label:"Recebido"}
function bindKanbanRefresh(){const button=document.querySelector("#refresh-kanban");if(button)button.addEventListener("click",()=>{renderProductionKanban();renderFinalizedProduction()});["#finalized-start","#finalized-end"].forEach(selector=>document.querySelector(selector)?.addEventListener("change",renderFinalizedProduction));document.querySelector("#filter-finalized-production")?.addEventListener("click",renderFinalizedProduction)}
function entryStage(entry){if(entry.stage)return normalizeStage(entry.stage);return entry.status==="finalizada"?"finalizado":"recebido"}function activeProductionStages(){return productionStages.filter(stage=>stage.id!=="finalizado")}function renderProductionKanban(){const board=document.querySelector("#production-kanban");if(!board)return;const entries=(state.services||[]).filter(entry=>entryStage(entry)!=="finalizado");board.innerHTML=activeProductionStages().map(stage=>{const items=entries.filter(entry=>entryStage(entry)===stage.id);return `<section class="kanban-column"><header><strong>${stage.label}</strong><span>${items.length}</span></header><div class="kanban-list">${items.length?items.map(renderKanbanCard).join(""):`<div class="kanban-empty">Sem entradas</div>`}</div></section>`}).join("")}
function renderKanbanCard(entry){const dueClass=entryDueClass(entry);const dueLabel=entryDueLabel(entry);return `<article class="kanban-card ${dueClass}"><strong>${esc(entry.patient||"Sem paciente")}</strong><span>${esc(entry.name||"Cliente não informado")}</span><span>${esc(entryServiceLabel(entry)||"Serviço não informado")}</span>${dueLabel?`<em class="due-alert">${esc(dueLabel)}</em>`:""}<div class="kanban-card-meta"><small>Prev.: ${formatDate(entry.expectedDate)||"-"}</small><small>${money(calculateEntryTotal(entry))}</small></div><div class="kanban-actions"><button type="button" title="Voltar etapa" onclick="moveEntryStage('${entry.id}',-1)">‹</button><button type="button" title="Avançar etapa" onclick="moveEntryStage('${entry.id}',1)">›</button><button type="button" title="Visualizar nota" onclick="viewEntryNote('${entry.id}')">V</button><button type="button" class="kanban-delete" title="Excluir entrada" onclick="deleteItem('services','${entry.id}')">Excluir</button></div></article>`}
function finalizedPeriod(){const startInput=document.querySelector("#finalized-start");const endInput=document.querySelector("#finalized-end");if(startInput&&!startInput.value)startInput.value=today.slice(0,8)+"01";if(endInput&&!endInput.value)endInput.value=today;return{start:startInput?.value||today.slice(0,8)+"01",end:endInput?.value||today}}function finalizedEntryDate(entry){return entry.exitDate||entry.entryDate||""}function finalizedProductionRows(){const {start,end}=finalizedPeriod();return (state.services||[]).filter(entry=>entryStage(entry)==="finalizado"||entry.status==="finalizada").filter(entry=>{const date=finalizedEntryDate(entry);if(!date)return false;if(start&&date<start)return false;if(end&&date>end)return false;return true}).sort((a,b)=>String(finalizedEntryDate(b)).localeCompare(String(finalizedEntryDate(a))))}function renderFinalizedProduction(){const list=document.querySelector("#finalized-production-list");if(!list)return;const rows=finalizedProductionRows();list.innerHTML=rows.length?rows.map(entry=>`<article class="finalized-production-card"><div><strong>${esc(entry.patient||"Sem paciente")}</strong><span>${esc(entry.name||"Cliente não informado")} | Nota ${esc(entry.noteNumber||"-")}</span></div><div><span>Saída</span><strong>${formatDate(finalizedEntryDate(entry))||"-"}</strong></div><div><span>Serviço</span><strong>${esc(entryServiceLabel(entry)||"Serviço")}</strong></div><div><span>Total</span><strong>${money(calculateEntryTotal(entry))}</strong></div><button type="button" class="text-button" onclick="viewEntryNote('${entry.id}')">Ver nota</button></article>`).join(""):`<div class="empty-state"><strong>Nenhum trabalho finalizado no período</strong><span>Altere as datas para consultar outros finalizados.</span></div>`}function moveEntryStage(id,direction){const entry=state.services.find(item=>item.id===id);if(!entry)return;const current=productionStages.findIndex(stage=>stage.id===normalizeStage(entry.stage||"recebido"));const next=Math.max(0,Math.min(productionStages.length-1,current+direction));entry.stage=productionStages[next].id;if(entry.stage==="finalizado"){entry.status="finalizada";entry.exitDate=today}else if(entry.status==="finalizada"){entry.status="aberta";entry.exitDate=""}saveState();render()}





function entryTotalAmount(entry){return Number(calculateEntryTotal(entry))||0}
function sumEntryOrders(items=state.services){return items.reduce((total,entry)=>total+entryTotalAmount(entry),0)}
function renderEntryTotalSummary(){const box=document.querySelector("#entry-total-summary");if(!box)return;const entries=state.services||[];const open=entries.filter(entry=>(entry.status||"aberta")!=="finalizada");const finished=entries.filter(entry=>(entry.status||"aberta")==="finalizada");box.innerHTML=`<div><span>Total dos pedidos</span><strong>${money(sumEntryOrders(entries))}</strong></div><div><span>Pedidos abertos</span><strong>${money(sumEntryOrders(open))}</strong></div><div><span>Pedidos finalizados</span><strong>${money(sumEntryOrders(finished))}</strong></div>`}

function cloudConfig(){return window.LAB_SUPABASE_CONFIG||{}}
function initCloud(){const config=cloudConfig();if(!config.url||!config.publishableKey||!window.supabase){setCloudStatus("Local");return null}cloudClient=window.supabase.createClient(config.url,config.publishableKey,{auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:false}});setCloudStatus("Nuvem pronta");return cloudClient}
function setCloudStatus(text,details=""){const label=document.querySelector("#cloud-status");if(label){label.textContent=text;label.title=details||text}}function showLoginError(message){const error=document.querySelector("#login-error");if(error)error.textContent=message||""}
function supabaseLoginEmail(access){const value=String(access||"").trim().toLowerCase();if(!value)return"";if(value.includes("@"))return value;const domain=cloudConfig().loginDomain||"labsoftware.local";return `${value}@${domain}`}
function supabaseLoginLabel(email){const domain=cloudConfig().loginDomain||"labsoftware.local";return String(email||"").endsWith(`@${domain}`)?String(email).replace(`@${domain}`,""):email}
function cleanAccountName(value){return String(value||"").trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/[^a-z0-9._-]/g,"-").replace(/-+/g,"-").replace(/^-|-$/g,"")}
async function loginWithSupabase(access,password){if(!cloudClient)initCloud();if(!cloudClient)throw new Error("Supabase não configurado.");const email=supabaseLoginEmail(String(access||"").includes("@")?access:cleanAccountName(access));const {data,error}=await cloudClient.auth.signInWithPassword({email,password});if(error)throw new Error("Usuário ou senha do Supabase inválidos.");const user=data.user;if(!user)throw new Error("Login não confirmado no Supabase.");cloudLabId=await ensureCloudLab();await assertCloudAccess();await loadCloudState(user);const label=supabaseLoginLabel(user.email);sessionStorage.setItem("lab-auth","ok");sessionStorage.setItem("lab-user",JSON.stringify({id:user.id,name:label,username:label,role:"Nuvem",source:"supabase"}));setCloudStatus("Nuvem conectada");applyAuthState();render()}
async function restoreCloudSession(){if(!cloudClient)return false;try{setCloudStatus("Carregando nuvem...");const {data}=await cloudClient.auth.getSession();if(!data.session?.user){setCloudStatus("Local");return false}cloudLabId=await ensureCloudLab();await assertCloudAccess();await loadCloudState(data.session.user);sessionStorage.setItem("lab-auth","ok");sessionStorage.setItem("lab-user",JSON.stringify({id:data.session.user.id,name:data.session.user.email,username:data.session.user.email,role:"Nuvem",source:"supabase"}));setCloudStatus("Nuvem conectada");applyAuthState();render();return true}catch(err){console.error("Erro na nuvem",err);const message=err?.message||"Não foi possível conectar na nuvem.";sessionStorage.removeItem("lab-auth");sessionStorage.removeItem("lab-user");setCloudStatus("Erro na nuvem",message);showLoginError(message);applyAuthState();return false}}
async function ensureCloudLab(){const {data,error}=await cloudClient.rpc("ensure_my_lab");if(error)throw new Error(`Erro no Supabase: ${error.message||"execute novamente o supabase-setup.sql"}`);return data}
async function assertCloudAccess(){if(!cloudClient||!cloudLabId)return;const {data,error}=await cloudClient.from("labs").select("status,suspended_reason,suspended_until").eq("id",cloudLabId).maybeSingle();if(error){const message=String(error.message||"");if(message.includes("status")&&message.includes("does not exist")){setCloudStatus("Nuvem conectada","Controle de assinatura pendente: execute o supabase-setup.sql atualizado.");return}throw new Error(`Erro ao verificar assinatura: ${error.message||"verifique o Supabase"}`)}if(data?.status&&data.status!=="active"){const until=data.suspended_until?` até ${formatDate(data.suspended_until)}`:"";const reason=data.suspended_reason?` Motivo: ${data.suspended_reason}`:"";throw new Error(`Conta suspensa${until}.${reason} Fale com o suporte pelo WhatsApp.`)}}
async function loadCloudState(user){if(!cloudClient||!cloudLabId)return;cloudRestoring=true;try{const {data,error}=await cloudClient.from("lab_state").select("data").eq("lab_id",cloudLabId).maybeSingle();if(error)throw new Error(`Erro ao carregar dados da nuvem: ${error.message||"verifique as permissões do Supabase"}`);if(data?.data){state=cleanSeededCategories({...emptyLabState(user),...data.data});localStorage.setItem(storageKey(),JSON.stringify(state))}else{state=emptyLabState(user);localStorage.setItem(storageKey(),JSON.stringify(state));await saveStateToCloud()}}finally{cloudRestoring=false}}
function queueCloudSave(){if(cloudRestoring||!cloudClient||!cloudLabId)return;clearTimeout(cloudSaveTimer);setCloudStatus("Salvando...");cloudSaveTimer=setTimeout(()=>saveStateToCloud(),700)}
async function saveStateToCloud(){if(!cloudClient||!cloudLabId)return;const {error}=await cloudClient.from("lab_state").upsert({lab_id:cloudLabId,data:state,updated_at:new Date().toISOString()});if(error){setCloudStatus("Erro ao salvar");throw new Error(`Erro ao salvar na nuvem: ${error.message||"verifique as permissões do Supabase"}`)}setCloudStatus("Nuvem conectada")}function companyData(){state.company={...structuredClone(defaultData.company),...(state.company||{})};if(state.company.name==="Lab_Software")state.company.name="LabNext";if(state.company.supportName==="Suporte Lab_Software")state.company.supportName="Suporte LabNext";return state.company}
function companyInitials(){const name=companyData().name||"LabNext";const ignore=new Set(["de","da","do","das","dos","e","laboratorio","laboratório","lab"]);const parts=String(name).normalize("NFD").replace(/[\u0300-\u036f]/g,"").split(/\s|_|-/).filter(Boolean).filter(part=>!ignore.has(part.toLowerCase()));const initials=(parts.length?parts:String(name).split(/\s|_|-/).filter(Boolean)).slice(0,3).map(part=>part[0]).join("").toUpperCase();return initials||"LN"}
function restoreRememberedLogin(){const form=document.querySelector("#login-form");if(!form)return;try{const saved=JSON.parse(localStorage.getItem(REMEMBER_LOGIN_KEY)||"null");if(!saved?.username)return;if(form.elements.username)form.elements.username.value=saved.username;if(form.elements.rememberAccess)form.elements.rememberAccess.checked=true;if(form.elements.password)form.elements.password.value=""}catch{localStorage.removeItem(REMEMBER_LOGIN_KEY)}}function updateRememberedLogin(form,access){if(!form?.elements.rememberAccess)return;if(form.elements.rememberAccess.checked)localStorage.setItem(REMEMBER_LOGIN_KEY,JSON.stringify({username:access,updatedAt:new Date().toISOString()}));else localStorage.removeItem(REMEMBER_LOGIN_KEY)}function bindLogin(){const form=document.querySelector("#login-form");const logout=document.querySelector("#logout-button");if(form)form.addEventListener("submit",async event=>{event.preventDefault();const data=Object.fromEntries(new FormData(form).entries());const access=String(data.username||"").trim();updateRememberedLogin(form,access);const error=document.querySelector("#login-error");if(error)error.textContent="";const localResult=findLoginUser(data.username,data.password);if(localResult.blocked){if(error)error.textContent="Este usuário está bloqueado. Use outro acesso ou desbloqueie no cadastro de usuários.";return}if(localResult.ok){sessionStorage.setItem("lab-auth","ok");sessionStorage.setItem("lab-user",JSON.stringify(localResult.session));applyAuthState();render();return}if(cloudClient){try{setCloudStatus("Entrando na nuvem...");await loginWithSupabase(access,data.password);return}catch(err){console.error("Erro no login da nuvem",err);const message=err?.message||"Não foi possível entrar pela nuvem.";if(error)error.textContent=message;setCloudStatus("Erro na nuvem",message);return}}if(error)error.textContent="Usuário ou senha inválidos."});if(logout)logout.addEventListener("click",async()=>{if(cloudClient)await cloudClient.auth.signOut();cloudLabId=null;sessionStorage.removeItem("lab-auth");sessionStorage.removeItem("lab-user");showLoginError("");setCloudStatus("Local");applyAuthState()})}function findLoginUser(username,password){const access=String(username||"").trim();const pass=String(password||"");const company=companyData();if(access===String(company.loginUser||"").trim()&&pass===String(company.loginPass||""))return{ok:true,session:{name:company.owner||company.name||"Administrador",username:access,role:"Administrador",source:"empresa"}};const user=(state.users||[]).find(item=>normalizeName(item.username)===normalizeName(access));if(user&&String(user.password||"")===pass){if(user.status==="bloqueado")return{blocked:true};return{ok:true,session:{id:user.id,name:user.name||user.username,username:user.username,role:user.role||"Atendimento",source:"usuarios"}}}return{ok:false}}function currentSessionUser(){try{return JSON.parse(sessionStorage.getItem("lab-user")||"null")}catch{return null}}function isOwnerEmail(email){return OWNER_EMAILS.includes(String(email||"").trim().toLowerCase())}function currentUserEmail(){const user=currentSessionUser();return String(user?.username||user?.name||"").trim().toLowerCase()}function renderCurrentUser(){const label=document.querySelector("#current-user-label");if(!label)return;const user=currentSessionUser();label.textContent=user?`${user.name} - ${user.role}`:"";renderOwnerTools()}
function bindSignupToggle(){const open=document.querySelector("#toggle-signup");const cancel=document.querySelector("#cancel-signup");const login=document.querySelector("#login-form");const signup=document.querySelector("#lab-signup-form");const showSignup=()=>{if(signup)signup.hidden=false;if(login)login.classList.add("login-card-muted");signup?.scrollIntoView({behavior:"smooth",block:"nearest"})};const hideSignup=()=>{if(signup)signup.hidden=true;if(login)login.classList.remove("login-card-muted")};open?.addEventListener("click",showSignup);cancel?.addEventListener("click",hideSignup)}function bindLabSignup(){const form=document.querySelector("#lab-signup-form");if(!form)return;form.addEventListener("submit",async event=>{event.preventDefault();const data=Object.fromEntries(new FormData(form).entries());const errorBox=document.querySelector("#signup-error");const resendButton=document.querySelector("#resend-signup-confirmation");if(errorBox)errorBox.textContent="";if(resendButton)resendButton.hidden=true;if(!cloudClient){if(errorBox)errorBox.textContent="Supabase não configurado.";return}const email=String(data.email||"").trim().toLowerCase();if(!email||!email.includes("@")){if(errorBox)errorBox.textContent="Informe um e-mail válido para criar a conta.";return}try{setCloudStatus("Criando conta...");const labName=String(data.labName||"").trim();const {data:signup,error}=await cloudClient.auth.signUp({email,password:data.password,options:{emailRedirectTo:window.location.origin,data:{lab_name:labName,account_name:email,account_email:email}}});if(error)throw error;if(!signup.session){if(errorBox)errorBox.textContent="Conta criada. Enviamos um e-mail de confirmação para o cliente. Depois de confirmar, ele poderá entrar no sistema.";if(resendButton)resendButton.hidden=false;setCloudStatus("Confirmação enviada");return}cloudLabId=await ensureCloudLab();state=emptyLabState({email,user_metadata:{lab_name:labName||"LabNext"}});await saveStateToCloud();localStorage.setItem(storageKey(),JSON.stringify(state));sessionStorage.setItem("lab-auth","ok");sessionStorage.setItem("lab-user",JSON.stringify({id:signup.user.id,name:email,username:email,role:"Dono",source:"supabase"}));setCloudStatus("Nuvem conectada");applyAuthState();render();form.reset()}catch(err){if(errorBox)errorBox.textContent=err.message||"Não foi possível criar a conta.";setCloudStatus("Erro ao criar conta")}})}function bindSignupResend(){const button=document.querySelector("#resend-signup-confirmation");const form=document.querySelector("#lab-signup-form");if(!button||!form)return;button.addEventListener("click",async()=>{const errorBox=document.querySelector("#signup-error");const email=String(form.elements.email?.value||"").trim().toLowerCase();if(errorBox)errorBox.textContent="";if(!cloudClient){if(errorBox)errorBox.textContent="Supabase não configurado.";return}if(!email||!email.includes("@")){if(errorBox)errorBox.textContent="Informe o e-mail da conta para reenviar a confirmação.";return}try{setCloudStatus("Reenviando confirmação...");const {error}=await cloudClient.auth.resend({type:"signup",email,options:{emailRedirectTo:window.location.origin}});if(error)throw error;if(errorBox)errorBox.textContent="Reenviamos a confirmação. Confira a caixa de entrada e o spam.";setCloudStatus("Confirmação reenviada")}catch(err){if(errorBox)errorBox.textContent=err.message||"Não foi possível reenviar a confirmação.";setCloudStatus("Erro ao reenviar")}})}function applyAuthState(){const logged=sessionStorage.getItem("lab-auth")==="ok";const login=document.querySelector("#login-screen");const app=document.querySelector("#app-shell");if(login)login.hidden=logged;if(app)app.hidden=!logged;renderCompany();renderCurrentUser()}
function bindCompanyForm(){const form=document.querySelector("#company-form");if(!form)return;form.addEventListener("submit",event=>{event.preventDefault();state.company={...companyData(),...Object.fromEntries(new FormData(form).entries())};saveState();renderCompany();alert("Dados da empresa salvos.")})}function bindPasswordChange(){const button=document.querySelector("#change-account-password");if(!button)return;button.addEventListener("click",async()=>{if(!cloudClient)return alert("A troca de senha online precisa da nuvem conectada.");const {data,error}=await cloudClient.auth.getUser();if(error||!data?.user?.email)return alert("Entre com o e-mail da conta para alterar a senha online.");const password=prompt("Digite a nova senha da conta online. Use no mínimo 6 caracteres.");if(password===null)return;if(String(password).length<6)return alert("A senha precisa ter no mínimo 6 caracteres.");const confirm=prompt("Confirme a nova senha.");if(confirm!==password)return alert("As senhas não conferem.");const result=await cloudClient.auth.updateUser({password});if(result.error)return alert(result.error.message||"Não foi possível alterar a senha.");alert("Senha online alterada com sucesso.")})}function isOwnerSession(){return !!(cloudLabId&&isOwnerEmail(currentUserEmail()))}function renderOwnerTools(){const owner=isOwnerSession();const box=document.querySelector("#owner-tools");if(box)box.hidden=!owner;document.querySelectorAll(".owner-only").forEach(item=>item.hidden=!owner);if(owner)startSubscriptionWatcher();else stopSubscriptionWatcher();const active=document.querySelector("#subscriptions-view.active");if(active&&!owner)showView("dashboard")}function bindOwnerReset(){const button=document.querySelector("#reset-cloud-account");if(!button)return;button.addEventListener("click",async()=>{if(!cloudClient||!cloudLabId)return alert("Entre pela nuvem antes de usar esta opção.");const {data,error}=await cloudClient.auth.getUser();const email=String(data?.user?.email||"").toLowerCase();if(error||!isOwnerEmail(email))return alert("Esta opção é exclusiva do dono do sistema.");const typed=prompt("Para zerar esta conta, digite ZERAR");if(typed!=="ZERAR")return;state=emptyLabState(data.user);localStorage.setItem(storageKey(),JSON.stringify(state));await saveStateToCloud();render();alert("Conta zerada com sucesso.")})}function subscriptionStatusLabel(status){return {active:"Ativa",suspended:"Suspensa",blocked:"Bloqueada",cancelled:"Cancelada"}[status]||status||"Ativa"}function subscriptionStatusClass(status){return status==="active"?"amount-in":"amount-out"}function bindSubscriptionAdmin(){document.querySelector("#refresh-subscriptions")?.addEventListener("click",renderSubscriptionAdmin);document.querySelector("#subscriptions-table")?.addEventListener("click",async event=>{const button=event.target.closest("[data-subscription-action]");if(!button)return;await updateSubscriptionStatus(button.dataset.labId,button.dataset.subscriptionAction)})}function knownLabIds(){try{return JSON.parse(localStorage.getItem(OWNER_NOTIFICATION_KEY)||"null")}catch{return null}}function saveKnownLabIds(rows){localStorage.setItem(OWNER_NOTIFICATION_KEY,JSON.stringify((rows||[]).map(item=>item.id).filter(Boolean)))}function updateSubscriptionBadge(count=0){const button=document.querySelector('[data-view="subscriptions"]');if(!button)return;button.innerHTML=`Admin Assinaturas${count?` <span class="nav-badge">${count}</span>`:""}`}function showNewLoginNotice(newLabs){let box=document.querySelector("#new-login-alert");const panel=document.querySelector("#subscriptions-view .subscription-panel");if(!box&&panel){box=document.createElement("div");box.id="new-login-alert";box.className="new-login-alert";panel.insertBefore(box,panel.querySelector(".table-wrap"))}if(box){box.hidden=!newLabs.length;box.innerHTML=newLabs.length?`<strong>Novo login cadastrado</strong><span>${newLabs.map(lab=>esc(lab.name||lab.account_name||"Novo laboratório")).join(", ")}</span>`:""}}function notifyNewLabs(rows){const known=knownLabIds();if(!known){saveKnownLabIds(rows);updateSubscriptionBadge(0);showNewLoginNotice([]);return}const knownSet=new Set(known);const newLabs=(rows||[]).filter(lab=>lab.id&&!knownSet.has(lab.id));updateSubscriptionBadge(newLabs.length);showNewLoginNotice(newLabs);if(newLabs.length){alert(`Novo login cadastrado: ${newLabs.map(lab=>lab.name||lab.account_name||"Novo laboratório").join(", ")}`);saveKnownLabIds(rows)}}function startSubscriptionWatcher(){if(subscriptionPollTimer||!isOwnerSession())return;renderSubscriptionAdmin();subscriptionPollTimer=setInterval(()=>{if(isOwnerSession())renderSubscriptionAdmin()},60000)}function stopSubscriptionWatcher(){if(subscriptionPollTimer){clearInterval(subscriptionPollTimer);subscriptionPollTimer=null}updateSubscriptionBadge(0)}async function renderSubscriptionAdmin(){const table=document.querySelector("#subscriptions-table");const status=document.querySelector("#subscriptions-status");if(!table)return;if(!isOwnerSession()){table.innerHTML="";showNewLoginNotice([]);if(status)status.textContent="Área exclusiva do dono do sistema.";return}if(status)status.textContent="Carregando laboratórios...";try{const {data,error}=await cloudClient.rpc("list_subscription_labs");if(error)throw error;const rows=data||[];notifyNewLabs(rows);table.innerHTML=`<thead><tr><th>Laboratório</th><th>Conta</th><th>Status</th><th>Motivo</th><th>Criado em</th><th>Ações</th></tr></thead><tbody>${rows.length?rows.map(lab=>`<tr><td><strong>${esc(lab.name||"LabNext")}</strong><small>${esc(lab.id||"")}</small></td><td>${esc(lab.account_name||"Não informado")}</td><td><span class="badge ${subscriptionStatusClass(lab.status)}">${subscriptionStatusLabel(lab.status)}</span></td><td>${esc(lab.suspended_reason||"")}</td><td>${formatDate(String(lab.created_at||"").slice(0,10))}</td><td><div class="row-actions"><button class="icon-button" title="Liberar" data-lab-id="${esc(lab.id)}" data-subscription-action="active">A</button><button class="icon-button danger" title="Suspender" data-lab-id="${esc(lab.id)}" data-subscription-action="suspended">S</button><button class="icon-button danger" title="Bloquear" data-lab-id="${esc(lab.id)}" data-subscription-action="blocked">B</button><button class="icon-button danger" title="Cancelar" data-lab-id="${esc(lab.id)}" data-subscription-action="cancelled">C</button></div></td></tr>`).join(""):`<tr><td colspan="6">${emptyState()}</td></tr>`}</tbody>`;if(status)status.textContent=`${rows.length} laboratório(s) encontrado(s).`}catch(err){if(status)status.textContent=err.message||"Não foi possível carregar assinaturas.";table.innerHTML=""}}async function updateSubscriptionStatus(labId,newStatus){if(!isOwnerSession())return alert("Esta opção é exclusiva do dono do sistema.");const reason=newStatus==="active"?"":prompt("Motivo da alteração",newStatus==="suspended"?"Mensalidade em atraso":"Acesso bloqueado pelo administrador");if(newStatus!=="active"&&reason===null)return;const {error}=await cloudClient.rpc("set_lab_subscription_status",{target_lab:labId,new_status:newStatus,reason:reason||null,until_date:null});if(error)return alert(error.message||"Não foi possível alterar a assinatura.");await renderSubscriptionAdmin();alert(newStatus==="active"?"Conta liberada.":"Conta alterada com sucesso.")}
function renderCompany(){const company=companyData();document.querySelectorAll(".brand strong").forEach(item=>item.textContent=company.name||"LabNext");document.querySelectorAll(".brand .brand-mark").forEach(item=>item.textContent=companyInitials());const eyebrow=document.querySelector(".eyebrow");if(eyebrow)eyebrow.textContent=company.name?"Laboratório de prótese dentária":"Laboratório de prótese dentária";const loginName=document.querySelector("#login-company-name");if(loginName)loginName.textContent=company.name||"LabNext";const form=document.querySelector("#company-form");if(form){Object.entries(company).forEach(([key,value])=>{if(form.elements[key])form.elements[key].value=value||""})}const preview=document.querySelector("#company-preview");if(preview)preview.innerHTML=`<strong>${esc(company.name||"")}</strong><span>E-mail: ${esc(company.email||"Não informado")}</span><span>Telefone: ${esc(company.phone||"Não informado")}</span><span>Documento: ${esc(company.document||"Não informado")}</span><span>Endereço: ${esc(company.address||"Não informado")}</span><span>Usuário de acesso: ${esc(company.loginUser||"")}</span>`;renderOwnerTools()}

function supportWhatsAppLink(value){const digits=String(value||"").replace(/\D/g,"");const phone=digits.startsWith("55")?digits:`55${digits||"18997476202"}`;return `https://wa.me/${phone}`}
function renderSupport(){const company=companyData();const name=company.supportName||"Suporte LabNext";const whatsapp=company.supportWhatsapp||"(18) 99747-6202";const nameEl=document.querySelector("#support-name");const numberEl=document.querySelector("#support-whatsapp-number");const link=document.querySelector("#support-whatsapp-link");if(nameEl)nameEl.textContent=name;if(numberEl)numberEl.textContent=whatsapp;if(link){link.href=supportWhatsAppLink(whatsapp);link.textContent="Chamar no WhatsApp"}}
function parseAmountValue(value){if(typeof value==="number")return value;const text=String(value||"").trim();if(!text)return 0;const normalized=text.includes(",")?text.replace(/\./g,"").replace(",","."):text;return Number(normalized.replace(/[^\d.-]/g,""))||0}
function transactionStatus(item){return String(item?.status||"").trim().toLowerCase()}
function transactionIsPaid(item){const status=transactionStatus(item);return status==="pago"||status==="compensado"||status==="recebido"}
function transactionIsOut(item){const type=String(item?.type||"").trim().toLowerCase();return type==="saida"||type==="saída"}
function transactionAmount(item){const amount=parseAmountValue(item.amount);return transactionIsOut(item)?-amount:amount}
function transactionIsOverduePendingOut(item){return transactionIsOut(item)&&transactionStatus(item)==="pendente"&&item.date&&item.date<today}function cashbookRowClass(item){if(transactionIsOverduePendingOut(item))return "cashbook-row-overdue";if(transactionStatus(item)==="pendente")return "cashbook-row-pending";return transactionIsOut(item)?"cashbook-row-out":"cashbook-row-in"}
function renderCashBook(){const table=document.querySelector("#cashbook-table");const summary=document.querySelector("#cashbook-summary");if(!table||!summary)return;const rows=[...(state.transactions||[])].sort((a,b)=>String(a.date||"").localeCompare(String(b.date||"")));const paid=rows.filter(transactionIsPaid);const income=paid.filter(item=>!transactionIsOut(item)).reduce((total,item)=>total+parseAmountValue(item.amount),0);const outcome=paid.filter(transactionIsOut).reduce((total,item)=>total+parseAmountValue(item.amount),0);const pending=rows.filter(item=>transactionStatus(item)==="pendente").reduce((total,item)=>total+parseAmountValue(item.amount),0);summary.innerHTML=`<div><span>Entradas pagas</span><strong class="amount-in">${money(income)}</strong></div><div><span>Saídas pagas</span><strong class="amount-out">${money(outcome)}</strong></div><div><span>Saldo em caixa</span><strong class="${income-outcome>=0?"amount-in":"amount-out"}">${money(income-outcome)}</strong></div><div><span>Pendentes</span><strong>${money(pending)}</strong></div>`;let balance=0;table.innerHTML=`<thead><tr><th>Data</th><th>Histórico</th><th>Categoria</th><th>Entrada</th><th>Saída</th><th>Status</th><th>Saldo</th><th>Ações</th></tr></thead><tbody>${rows.length?rows.map(item=>{const amount=parseAmountValue(item.amount);const isOut=transactionIsOut(item);if(transactionIsPaid(item))balance+=transactionAmount(item);return `<tr class="${cashbookRowClass(item)}"><td>${formatDate(item.date)}</td><td>${esc(item.description||"")}</td><td><span class="badge">${esc(item.category||"Sem categoria")}</span></td><td>${!isOut?money(amount):"-"}</td><td>${isOut?money(amount):"-"}</td><td><span class="badge">${esc(item.status||"")}${transactionIsOverduePendingOut(item)?" - Vencida":""}</span></td><td><strong>${transactionIsPaid(item)?money(balance):"-"}</strong></td><td><button type="button" class="text-button" onclick="editTransactionFromCashbook('${item.id}')">Editar</button></td></tr>`}).join(""):`<tr><td colspan="8">${emptyState()}</td></tr>`}</tbody>`}
function bindCashBookPrint(){const button=document.querySelector("#print-cashbook");if(!button)return;button.addEventListener("click",()=>{document.body.classList.add("printing-cashbook");window.print();setTimeout(()=>document.body.classList.remove("printing-cashbook"),500)})}

function extractPeriod(){const start=document.querySelector("#extract-start")?.value||today.slice(0,8)+"01";const end=document.querySelector("#extract-end")?.value||today;return {start,end}}
function financialExtractRows(){const {start,end}=extractPeriod();return [...(state.transactions||[])].filter(item=>{const date=item.date||"";if(!date)return false;if(start&&date<start)return false;if(end&&date>end)return false;return true}).sort((a,b)=>String(a.date||"").localeCompare(String(b.date||"")))}
function renderFinancialExtract(){const table=document.querySelector("#financial-extract-table");const summary=document.querySelector("#financial-extract-summary");const header=document.querySelector("#financial-extract-header");if(!table||!summary)return;const startInput=document.querySelector("#extract-start");const endInput=document.querySelector("#extract-end");if(startInput&&!startInput.value)startInput.value=today.slice(0,8)+"01";if(endInput&&!endInput.value)endInput.value=today;const {start,end}=extractPeriod();const rows=financialExtractRows();const paidRows=rows.filter(transactionIsPaid);const income=paidRows.filter(item=>!transactionIsOut(item)).reduce((total,item)=>total+parseAmountValue(item.amount),0);const outcome=paidRows.filter(transactionIsOut).reduce((total,item)=>total+parseAmountValue(item.amount),0);const pending=rows.filter(item=>transactionStatus(item)==="pendente").reduce((total,item)=>total+parseAmountValue(item.amount),0);const balance=income-outcome;if(header)header.innerHTML=documentHeaderMarkup("Extrato do livro caixa",`Período: ${formatDate(start)} até ${formatDate(end)}`,"<span>Entradas e saídas cadastradas no livro caixa</span>");summary.innerHTML=`<div><span>Total entradas</span><strong class="amount-in">${money(income)}</strong></div><div><span>Total saídas</span><strong class="amount-out">${money(outcome)}</strong></div><div><span>Saldo do período</span><strong class="${balance>=0?"amount-in":"amount-out"}">${money(balance)}</strong></div><div><span>Pendentes</span><strong>${money(pending)}</strong></div>`;let running=0;table.innerHTML=`<thead><tr><th>Data</th><th>Descrição do lançamento</th><th>Categoria</th><th>Entrada</th><th>Saída</th><th>Saldo</th></tr></thead><tbody>${rows.length?rows.map(item=>{const amount=parseAmountValue(item.amount);const isOut=transactionIsOut(item);if(transactionIsPaid(item))running+=transactionAmount(item);return `<tr class="${cashbookRowClass(item)}"><td>${formatDate(item.date)}</td><td><strong>${esc(item.description||"")}</strong><small>${isOut?"Saída":"Entrada"} | ${esc(item.status||"")}${transactionIsOverduePendingOut(item)?" | Vencida":""}</small></td><td><span class="badge">${esc(item.category||"Sem categoria")}</span></td><td>${!isOut?money(amount):"-"}</td><td>${isOut?money(amount):"-"}</td><td><strong>${transactionIsPaid(item)?money(running):"-"}</strong></td></tr>`}).join(""):`<tr><td colspan="6">${emptyState()}</td></tr>`}</tbody>`}
function hideFinancialExtractPreview(){document.body.classList.remove("previewing-financial-extract")}
function printFinancialExtract(){renderFinancialExtract();document.body.classList.add("printing-financial-extract");window.print();setTimeout(()=>document.body.classList.remove("printing-financial-extract"),500)}
function ensureFinancialPreviewToolbar(){let toolbar=document.querySelector("#financial-preview-toolbar");if(toolbar)return;toolbar=document.createElement("div");toolbar.id="financial-preview-toolbar";toolbar.className="financial-preview-toolbar";toolbar.innerHTML=`<button type="button" class="ghost-button" id="close-financial-preview">Voltar</button><button type="button" id="preview-print-financial-extract">Imprimir</button>`;document.body.append(toolbar);toolbar.querySelector("#close-financial-preview").addEventListener("click",hideFinancialExtractPreview);toolbar.querySelector("#preview-print-financial-extract").addEventListener("click",printFinancialExtract)}
function showFinancialExtractPreview(){renderFinancialExtract();ensureFinancialPreviewToolbar();document.body.classList.add("previewing-financial-extract");window.scrollTo({top:0,behavior:"smooth"})}
function bindFinancialExtract(){const button=document.querySelector("#generate-financial-extract");const print=document.querySelector("#print-financial-extract");button?.addEventListener("click",showFinancialExtractPreview);["#extract-start","#extract-end"].forEach(selector=>document.querySelector(selector)?.addEventListener("change",renderFinancialExtract));print?.addEventListener("click",printFinancialExtract);document.addEventListener("keydown",event=>{if(event.key==="Escape")hideFinancialExtractPreview()})}
function paymentClientNames(){return [...new Set([...(state.clients||[]).map(item=>item.name),...(state.services||[]).map(item=>item.name)].filter(Boolean))].sort((a,b)=>a.localeCompare(b,"pt-BR"))}
function populatePaymentEntrySelect(){const select=document.querySelector("#payment-entry-select");if(!select)return;const selected=select.value;const names=paymentClientNames();select.innerHTML='<option value="">Selecione o cliente</option>'+names.map(name=>`<option value="${esc(name)}">${esc(name)}</option>`).join("");select.value=names.includes(selected)?selected:""}
function showFinanceTab(tab){document.querySelector(`[data-finance-tab="${tab}"]`)?.click()}
function clientPaymentRows(){return [...(state.transactions||[])].filter(item=>item.type==="entrada"&&item.clientName).sort((a,b)=>String(b.date||"").localeCompare(String(a.date||"")))}
function renderClientPayments(){const table=document.querySelector("#client-payments-table");if(!table)return;const rows=clientPaymentRows();table.innerHTML=`<thead><tr><th>Data</th><th>Cliente</th><th>Valor</th><th>Status</th><th>A\u00e7\u00f5es</th></tr></thead><tbody>${rows.length?rows.map(item=>`<tr><td>${formatDate(item.date)}</td><td>${esc(item.clientName||"")}</td><td>${money(parseAmountValue(item.amount))}</td><td><span class="badge">${esc(item.status||"")}${transactionIsOverduePendingOut(item)?" - Vencida":""}</span></td><td><button type="button" class="text-button" onclick="editClientPayment('${item.id}')">Editar</button></td></tr>`).join(""):`<tr><td colspan="5">${emptyState()}</td></tr>`}</tbody>`}
function editTransactionFromCashbook(id){const item=(state.transactions||[]).find(entry=>entry.id===id);if(!item)return;if(item.clientName){editClientPayment(id);return}editItem("transactions",id)}
function editClientPayment(id){const item=(state.transactions||[]).find(entry=>entry.id===id);const form=document.querySelector("#client-payment-form");if(!item||!form)return;showView("finance");showFinanceTab("client");populatePaymentEntrySelect();form.elements.id.value=item.id||"";form.elements.clientName.value=item.clientName||"";form.elements.date.value=item.date||today;form.elements.amount.value=parseAmountValue(item.amount)||"";form.elements.status.value=item.status||"pago";if(form.elements.notes)form.elements.notes.value=item.notes||"";form.scrollIntoView({behavior:"smooth",block:"start"})}
function bindCheckForm(){const form=document.querySelector("#check-form");if(!form)return;form.addEventListener("submit",event=>{event.preventDefault();state.checks=state.checks||[];const data=Object.fromEntries(new FormData(form).entries());data.id=data.id||uid();const index=state.checks.findIndex(item=>item.id===data.id);index>=0?state.checks[index]=data:state.checks.push(data);syncCheckTransaction(data);saveState();form.reset();form.elements.id.value="";setDefaultDates();render();alert("Cheque cadastrado no livro caixa.")});document.querySelectorAll("[data-clear-check]").forEach(button=>button.addEventListener("click",()=>{form.reset();form.elements.id.value="";setDefaultDates()}))}
function syncCheckTransaction(check){state.transactions=state.transactions||[];state.transactions=state.transactions.filter(item=>item.checkId!==check.id);if(check.status==="devolvido")return;state.transactions.push({id:uid(),checkId:check.id,type:check.type,date:check.dueDate||check.date,description:`Cheque ${check.type==="saida"?"emitido":"recebido"} ${check.number||""} - ${check.person||check.bank||""}`,amount:check.amount,category:"Cheque",status:check.status==="compensado"?"pago":"pendente"})}
function renderChecks(){const table=document.querySelector("#checks-table");if(!table)return;state.checks=state.checks||[];const rows=[...state.checks].sort((a,b)=>String(b.date||"").localeCompare(String(a.date||"")));table.innerHTML=`<thead><tr><th>Data</th><th>Bom para</th><th>Tipo</th><th>Banco</th><th>Número</th><th>Responsável</th><th>Valor</th><th>Status</th><th>Ações</th></tr></thead><tbody>${rows.length?rows.map(check=>`<tr><td>${formatDate(check.date)}</td><td>${formatDate(check.dueDate)}</td><td><span class="badge">${check.type==="saida"?"Emitido":"Recebido"}</span></td><td>${esc(check.bank||"")}</td><td>${esc(check.number||"")}</td><td>${esc(check.person||"")}</td><td>${money(check.amount)}</td><td><span class="badge">${esc(check.status||"")}</span></td><td><div class="row-actions"><button class="icon-button" title="Editar" onclick="editCheck('${check.id}')">E</button><button class="icon-button danger" title="Excluir" onclick="deleteCheck('${check.id}')">Excluir</button></div></td></tr>`).join(""):`<tr><td colspan="9">${emptyState()}</td></tr>`}</tbody>`}
function editCheck(id){const check=(state.checks||[]).find(item=>item.id===id);const form=document.querySelector("#check-form");if(!check||!form)return;Object.entries(check).forEach(([key,value])=>{if(form.elements[key])form.elements[key].value=value||""});showView("finance");document.querySelector('[data-finance-tab="cashbook"]')?.click();form.scrollIntoView({behavior:"smooth",block:"start"})}
function deleteCheck(id){if(!confirm("Deseja excluir este cheque? O movimento ligado a ele será removido do caixa."))return;state.checks=(state.checks||[]).filter(item=>item.id!==id);state.transactions=(state.transactions||[]).filter(item=>item.checkId!==id);saveState();render()}
function populateCommissionStaffSelect(){const select=document.querySelector("#commission-staff");if(!select)return;const selected=select.value;const staff=state.staff||[];select.innerHTML='<option value="">Selecione o colaborador</option>'+staff.map(item=>`<option value="${item.id}">${esc(item.name||"")}</option>`).join("");select.value=staff.some(item=>item.id===selected)?selected:""}
function bindCommissionForm(){const form=document.querySelector("#commission-form");if(!form)return;form.addEventListener("submit",event=>{event.preventDefault();const data=Object.fromEntries(new FormData(form).entries());const staff=(state.staff||[]).find(item=>item.id===data.staffId);if(!staff)return alert("Selecione o colaborador.");const amount=Number(data.amount)||0;if(amount<=0)return alert("Informe o valor da comissão.");state.transactions=state.transactions||[];state.transactions.push({id:uid(),type:"saida",date:data.date||today,description:data.description||`Comissão colaborador - ${staff.name}`,amount,category:"Comissão",status:data.status||"pago",staffId:staff.id,staffName:staff.name,notes:data.notes||""});saveState();form.reset();setDefaultDates();render();alert("Comissão lançada no financeiro.")});document.querySelectorAll("[data-clear-commission]").forEach(button=>button.addEventListener("click",()=>{form.reset();setDefaultDates()}))}
function servicesReportRows(){const start=document.querySelector("#services-report-start")?.value||today.slice(0,8)+"01";const end=document.querySelector("#services-report-end")?.value||today;return (state.services||[]).filter(entry=>{const date=entry.exitDate||entry.entryDate||"";if(!date)return false;if(start&&date<start)return false;if(end&&date>end)return false;return true}).sort((a,b)=>String(a.exitDate||a.entryDate||"").localeCompare(String(b.exitDate||b.entryDate||"")))}
function renderServicesReport(){const table=document.querySelector("#services-report-table");const summary=document.querySelector("#services-report-summary");const list=document.querySelector("#services-report-list");if(!table||!summary)return;const startInput=document.querySelector("#services-report-start");const endInput=document.querySelector("#services-report-end");if(startInput&&!startInput.value)startInput.value=today.slice(0,8)+"01";if(endInput&&!endInput.value)endInput.value=today;const rows=servicesReportRows();const total=rows.reduce((sum,entry)=>sum+entryTotalAmount(entry),0);const qty=rows.reduce((sum,entry)=>sum+entryQuantity(entry),0);const finalized=rows.filter(entry=>entry.status==="finalizada").length;summary.innerHTML=`<div><span>Serviços encontrados</span><strong>${rows.length}</strong></div><div><span>Quantidade total</span><strong>${qty}</strong></div><div><span>Finalizados</span><strong>${finalized}</strong></div><div><span>Valor total</span><strong>${money(total)}</strong></div>`;table.innerHTML=`<thead><tr><th>Data</th><th>Nota</th><th>Cliente</th><th>Paciente</th><th>Serviço</th><th>Qtd.</th><th>Status</th><th>Total</th></tr></thead><tbody>${rows.length?rows.map(entry=>{const date=entry.exitDate||entry.entryDate||"";return `<tr><td>${formatDate(date)}</td><td>${esc(entry.noteNumber||"-")}</td><td>${esc(entry.name||"")}</td><td>${esc(entry.patient||"")}</td><td>${esc(entryServiceLabel(entry))}</td><td>${entryQuantity(entry)}</td><td><span class="badge">${esc(entry.status||"aberta")}</span></td><td><strong>${money(entryTotalAmount(entry))}</strong></td></tr>`}).join(""):`<tr><td colspan="8">${emptyState()}</td></tr>`}</tbody>`;if(list)list.innerHTML=rows.length?rows.map(entry=>{const date=entry.exitDate||entry.entryDate||"";return `<article class="service-report-item"><div><strong>${esc(entryServiceLabel(entry)||"Serviço")}</strong><span>${formatDate(date)} | Nota ${esc(entry.noteNumber||"-")} | ${esc(entry.status||"aberta")}</span></div><div><span>Cliente</span><strong>${esc(entry.name||"")}</strong></div><div><span>Paciente</span><strong>${esc(entry.patient||"")}</strong></div><div><span>Qtd.</span><strong>${entryQuantity(entry)}</strong></div><div><span>Total</span><strong>${money(entryTotalAmount(entry))}</strong></div></article>`}).join(""):emptyState()}
function bindServicesReport(){const button=document.querySelector("#generate-services-report");const print=document.querySelector("#print-services-report");button?.addEventListener("click",renderServicesReport);["#services-report-start","#services-report-end"].forEach(selector=>document.querySelector(selector)?.addEventListener("change",renderServicesReport));print?.addEventListener("click",()=>{renderServicesReport();document.body.classList.add("printing-services-report");window.print();setTimeout(()=>document.body.classList.remove("printing-services-report"),500)})}
function bindClientPaymentForm(){const form=document.querySelector("#client-payment-form");if(!form)return;form.addEventListener("submit",event=>{event.preventDefault();const data=Object.fromEntries(new FormData(form).entries());const clientName=String(data.clientName||"").trim();if(!clientName)return alert("Selecione o cliente para registrar o pagamento.");const amount=Number(data.amount)||0;if(amount<=0)return alert("Informe o valor pago.");const payment={id:data.id||uid(),type:"entrada",date:data.date||today,description:`Pagamento mensal - ${clientName}`,amount,category:"Receita",status:data.status||"pago",clientName,notes:data.notes||""};const index=(state.transactions||[]).findIndex(item=>item.id===payment.id);if(index>=0)state.transactions[index]=payment;else state.transactions.push(payment);saveState();form.reset();form.elements.id.value="";render();alert(index>=0?"Pagamento do cliente atualizado.":"Pagamento do cliente cadastrado no financeiro.")})}
function bindReceiptButton(){const button=document.querySelector("#create-receipt");const form=document.querySelector("#client-payment-form");if(!button||!form)return;button.addEventListener("click",()=>{const data=Object.fromEntries(new FormData(form).entries());const clientName=String(data.clientName||"").trim();const amount=Number(data.amount)||0;if(!clientName)return alert("Selecione o cliente para criar o recibo.");if(amount<=0)return alert("Informe o valor do recibo.");showReceipt({clientName,date:data.date||today,amount,status:data.status||"pago",notes:data.notes||""})})}
function showReceipt(receipt){const modal=document.querySelector("#note-modal");const content=document.querySelector("#note-content");if(!modal||!content)return;document.querySelector(".note-toolbar h2").textContent="Recibo";content.innerHTML=renderReceipt(receipt);modal.hidden=false}
function renderReceipt(receipt){const company=companyData();const number=`REC-${String(Date.now()).slice(-6)}`;return `<section class="receipt-paper modern-document">${documentHeaderMarkup("Recibo",number,`<span>${formatDate(receipt.date)}</span>`)}<section class="receipt-body"><p>Recebemos de <strong>${esc(receipt.clientName)}</strong> a importância de <strong>${money(receipt.amount)}</strong>, referente a pagamento de serviços laboratoriais de prótese dentária.</p>${receipt.notes?`<p><span>Observações:</span> ${esc(receipt.notes)}</p>`:""}</section><footer class="receipt-footer"><div><span>________________________________________</span><small>${esc(company.owner||company.name||"Responsável")}</small></div><div><span>________________________________________</span><small>${esc(receipt.clientName)}</small></div></footer></section>`}
function entryPaidAmount(entry){if(!entry)return 0;return (state.transactions||[]).filter(item=>item.type==="entrada"&&item.status==="pago"&&(item.entryId===entry.id||(entry.noteNumber&&String(item.noteNumber)===String(entry.noteNumber)))).reduce((total,item)=>total+(Number(item.amount)||0),0)}
function entryBillingDate(entry){return entry.exitDate||entry.entryDate||""}
function currentMonth(){return today.slice(0,7)}
function monthLabel(value){if(!value)return"";const [year,month]=value.split("-");return new Date(Number(year),Number(month)-1,1).toLocaleDateString("pt-BR",{month:"long",year:"numeric"})}
function normalizeName(value){return String(value||"").trim().toLowerCase()}
function clientPaymentsAmount(client,month){const wanted=normalizeName(client);return (state.transactions||[]).filter(item=>item.type==="entrada"&&item.status==="pago"&&String(item.date||"").startsWith(month)&&(wanted?normalizeName(item.clientName)===wanted:Boolean(item.clientName))).reduce((total,item)=>total+(Number(item.amount)||0),0)}
function populateBillingClientSelect(){const select=document.querySelector("#billing-client");if(!select)return;const selected=select.value;const names=[...new Set((state.services||[]).map(entry=>entry.name).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"pt-BR"));select.innerHTML='<option value="">Todos os clientes</option>'+names.map(name=>`<option value="${esc(name)}">${esc(name)}</option>`).join("");select.value=names.includes(selected)?selected:"";const month=document.querySelector("#billing-month");if(month&&!month.value)month.value=currentMonth()}
function getBillingRows(){const client=normalizeName(document.querySelector("#billing-client")?.value||"");const month=document.querySelector("#billing-month")?.value||currentMonth();return (state.services||[]).filter(entry=>{if(entry.status!=="finalizada")return false;const date=entryBillingDate(entry);if(!date||!date.startsWith(month))return false;if(client&&normalizeName(entry.name)!==client)return false;return true}).sort((a,b)=>String(entryBillingDate(a)).localeCompare(String(entryBillingDate(b))))}
function groupedBillingRows(rows){return rows.reduce((groups,entry)=>{const client=entry.name||"Cliente sem nome";if(!groups[client])groups[client]=[];groups[client].push(entry);return groups},{})}
function renderBillingReport(){const list=document.querySelector("#billing-report-list");const summary=document.querySelector("#billing-report-summary");const header=document.querySelector("#billing-statement-header");if(!list||!summary)return;const rows=getBillingRows();const selectedClient=document.querySelector("#billing-client")?.value||"";const client=selectedClient||"Todos os clientes";const month=document.querySelector("#billing-month")?.value||currentMonth();const groups=groupedBillingRows(rows);const clientNames=Object.keys(groups).sort((a,b)=>a.localeCompare(b,"pt-BR"));const billed=rows.reduce((total,entry)=>total+entryTotalAmount(entry),0);const received=selectedClient?clientPaymentsAmount(selectedClient,month):clientNames.reduce((total,name)=>total+clientPaymentsAmount(name,month),0);const open=Math.max(0,billed-received);if(header)header.innerHTML=documentHeaderMarkup("Extrato mensal para pagamento",`Cliente: ${esc(client)}`,`<span>Referência: ${esc(monthLabel(month))}</span>`);summary.innerHTML=`<div><span>Total mensal</span><strong>${money(billed)}</strong></div><div><span>Pagamento anterior</span><strong class="amount-in">${money(received)}</strong></div><div><span>Valor para pagamento</span><strong class="${open>0?"amount-out":"amount-in"}">${money(open)}</strong></div>`;list.innerHTML=clientNames.length?clientNames.map(name=>renderClientStatement(name,groups[name],month)).join(""):emptyState()}
function monthPeriod(month){const [year,rawMonth]=String(month||currentMonth()).split("-").map(Number);const last=new Date(year,rawMonth,0).getDate();return {start:`01/${String(rawMonth).padStart(2,"0")}/${year}`,end:`${String(last).padStart(2,"0")}/${String(rawMonth).padStart(2,"0")}/${year}`}}
function statementId(client,month){let hash=0;const text=`${client}-${month}`;for(let i=0;i<text.length;i++)hash=((hash<<5)-hash)+text.charCodeAt(i)|0;return `statement-${Math.abs(hash)}`}
function billingItemRows(entry){const items=entryItems(entry);const status=entry.status==="finalizada"?"Entregue":"Em aberto";const date=formatDate(entryBillingDate(entry));return (items.length?items:[normalizeEntryItem(entry)]).map((item,index)=>{const details=[item.category?`Setor: ${item.category}`:"",item.odontogram?`Dentes: ${item.odontogram}`:"",item.color?`Cor: ${item.color}`:""].filter(Boolean).join(" | ");return `<tr><td>${index===0?esc(entry.noteNumber||"-"):""}</td><td>${index===0?date:""}</td><td>${esc(item.quantity||"1")}</td><td><strong>${esc(item.service||entryServiceLabel(entry)||"Serviço")}</strong>${details?`<small>${esc(details)}</small>`:""}</td><td>${esc(entry.patient||"")}</td><td>${money(entryItemTotal(item))}</td><td>${money(0)}</td><td>${status}</td></tr>`}).join("")}
function renderClientStatement(client,rows,month){const total=rows.reduce((sum,entry)=>sum+entryTotalAmount(entry),0);const paid=clientPaymentsAmount(client,month);const due=Math.max(0,total-paid);const period=monthPeriod(month);const id=statementId(client,month);return `<article class="client-statement financial-statement modern-document" id="${id}"><div class="statement-actions"><strong>${esc(client)}</strong><div><button type="button" class="ghost-button" onclick="printStatementById(\x27${id}\x27)">Imprimir</button><button type="button" class="ghost-button" onclick="pdfStatementById(\x27${id}\x27)">Gerar PDF</button></div></div>${documentHeaderMarkup("Extrato mensal",monthLabel(month),`<span>Cliente: ${esc(client)}</span>`)}<section class="financial-title"><h3>Relatório Financeiro - Dr(a) ${esc(client)}</h3><strong>${esc(period.start)} à ${esc(period.end)}</strong></section><table class="financial-table"><thead><tr><th>OS</th><th>Data<br>Entrega</th><th>Qtd.</th><th>Serviço</th><th>Paciente</th><th>Valor</th><th>Valor Pago</th><th>Situação</th></tr></thead><tbody>${rows.map(entry=>billingItemRows(entry)).join("")}${paid>0?`<tr class="payment-row"><td></td><td>${formatDate(month+"-01")}</td><td></td><td>RECEBIDO</td><td></td><td></td><td>${money(paid)}</td><td></td></tr>`:""}</tbody></table><footer class="financial-summary"><div><strong>Total Entradas</strong> ${money(total)}</div><div><strong>Pagamento anterior</strong> ${money(paid)}</div><div><strong>Saldo</strong> ${money(due)}</div></footer></article>`}
function printStatementById(id){document.querySelectorAll(".client-statement").forEach(item=>item.classList.toggle("print-selected",item.id===id));document.body.classList.add("printing-single-statement");window.print();setTimeout(()=>{document.body.classList.remove("printing-single-statement");document.querySelectorAll(".client-statement").forEach(item=>item.classList.remove("print-selected"))},500)}
function pdfStatementById(id){alert("Para gerar o PDF, escolha Salvar como PDF na janela de impressão.");printStatementById(id)}
function printAllBillingReports(){const clientSelect=document.querySelector("#billing-client");if(clientSelect)clientSelect.value="";renderBillingReport();if(!document.querySelector(".client-statement"))return alert("Nenhum cliente com movimentação no período selecionado.");document.body.classList.add("printing-billing");window.print();setTimeout(()=>document.body.classList.remove("printing-billing"),500)}
function bindBillingReport(){const button=document.querySelector("#generate-billing-report");const print=document.querySelector("#print-billing-report");button?.addEventListener("click",renderBillingReport);["#billing-client","#billing-month"].forEach(selector=>document.querySelector(selector)?.addEventListener("change",renderBillingReport));print?.addEventListener("click",printAllBillingReports)}




































function reportPeriod(startSelector,endSelector){const startInput=document.querySelector(startSelector);const endInput=document.querySelector(endSelector);if(startInput&&!startInput.value)startInput.value=today.slice(0,8)+"01";if(endInput&&!endInput.value)endInput.value=today;return{start:startInput?.value||today.slice(0,8)+"01",end:endInput?.value||today}}
function entryReportDate(entry){return entry.exitDate||entry.entryDate||""}
function entriesInPeriod(start,end){return (state.services||[]).filter(entry=>{const date=entryReportDate(entry);if(!date)return false;if(start&&date<start)return false;if(end&&date>end)return false;return true})}
function serviceRankingRows(){const {start,end}=reportPeriod("#services-report-start","#services-report-end");const grouped=new Map();entriesInPeriod(start,end).forEach(entry=>{entryServiceRows(entry).forEach(item=>{const name=item.service||"Sem serviço";const current=grouped.get(name)||{service:name,count:0,quantity:0,total:0};current.count+=1;current.quantity+=Number(item.quantity)||0;current.total+=Number(item.total)||0;grouped.set(name,current)})});return [...grouped.values()].map(row=>({...row,average:row.count?row.total/row.count:0})).sort((a,b)=>b.quantity-a.quantity||b.total-a.total||a.service.localeCompare(b.service,"pt-BR"))}
function renderServiceRankingReport(){const table=document.querySelector("#service-ranking-table");if(!table)return;const rows=serviceRankingRows();table.innerHTML=`<thead><tr><th>Serviço</th><th>Lançamentos</th><th>Quantidade</th><th>Valor total</th><th>Ticket médio</th></tr></thead><tbody>${rows.length?rows.map(row=>`<tr><td>${esc(row.service)}</td><td>${row.count}</td><td>${row.quantity}</td><td><strong>${money(row.total)}</strong></td><td>${money(row.average)}</td></tr>`).join(""):`<tr><td colspan="6">${emptyState()}</td></tr>`}</tbody>`}
function bindServiceRankingReport(){document.querySelector("#generate-service-ranking")?.addEventListener("click",renderServiceRankingReport);document.querySelector("#export-service-ranking")?.addEventListener("click",()=>exportTableCsv("servicos-mais-lancados.csv",["Serviço","Lançamentos","Quantidade","Valor total","Ticket médio"],serviceRankingRows().map(row=>[row.service,row.count,row.quantity,row.total.toFixed(2),row.average.toFixed(2)])))}
function clientSpendingRows(){const {start,end}=reportPeriod("#client-spending-start","#client-spending-end");const grouped=new Map();entriesInPeriod(start,end).forEach(entry=>{const client=entry.name||"Sem cliente";const current=grouped.get(client)||{client,count:0,quantity:0,total:0};current.count+=1;current.quantity+=entryQuantity(entry);current.total+=entryTotalAmount(entry);grouped.set(client,current)});return [...grouped.values()].map(row=>({...row,average:row.count?row.total/row.count:0})).sort((a,b)=>b.total-a.total||a.client.localeCompare(b.client,"pt-BR"))}
function renderClientSpendingReport(){const table=document.querySelector("#client-spending-table");const summary=document.querySelector("#client-spending-summary");if(!table||!summary)return;const rows=clientSpendingRows();const total=rows.reduce((sum,row)=>sum+row.total,0);const quantity=rows.reduce((sum,row)=>sum+row.quantity,0);summary.innerHTML=`<div><span>Clientes no período</span><strong>${rows.length}</strong></div><div><span>Quantidade total</span><strong>${quantity}</strong></div><div><span>Total gasto</span><strong>${money(total)}</strong></div><div><span>Maior cliente</span><strong>${esc(rows[0]?.client||"-")}</strong></div>`;table.innerHTML=`<thead><tr><th>Cliente</th><th>Lançamentos</th><th>Quantidade</th><th>Total gasto</th><th>Ticket médio</th></tr></thead><tbody>${rows.length?rows.map(row=>`<tr><td>${esc(row.client)}</td><td>${row.count}</td><td>${row.quantity}</td><td><strong>${money(row.total)}</strong></td><td>${money(row.average)}</td></tr>`).join(""):`<tr><td colspan="6">${emptyState()}</td></tr>`}</tbody>`}
function bindClientSpendingReport(){document.querySelector("#generate-client-spending")?.addEventListener("click",renderClientSpendingReport);["#client-spending-start","#client-spending-end"].forEach(selector=>document.querySelector(selector)?.addEventListener("change",renderClientSpendingReport));document.querySelector("#export-client-spending")?.addEventListener("click",()=>exportTableCsv("clientes-que-mais-gastaram.csv",["Cliente","Lançamentos","Quantidade","Total gasto","Ticket médio"],clientSpendingRows().map(row=>[row.client,row.count,row.quantity,row.total.toFixed(2),row.average.toFixed(2)])))}
function profitExpenseRows(){const {start,end}=reportPeriod("#profit-expense-start","#profit-expense-end");return (state.transactions||[]).filter(item=>{const date=item.date||"";if(!date)return false;if(start&&date<start)return false;if(end&&date>end)return false;return true}).sort((a,b)=>String(a.date||"").localeCompare(String(b.date||"")))}
function renderProfitExpenseReport(){const table=document.querySelector("#profit-expense-table");const summary=document.querySelector("#profit-expense-summary");if(!table||!summary)return;const rows=profitExpenseRows();const paid=rows.filter(transactionIsPaid);const income=paid.filter(item=>!transactionIsOut(item)).reduce((sum,item)=>sum+parseAmountValue(item.amount),0);const expenses=paid.filter(transactionIsOut).reduce((sum,item)=>sum+parseAmountValue(item.amount),0);const balance=income-expenses;summary.innerHTML=`<div><span>Faturamento</span><strong class="amount-in">${money(income)}</strong></div><div><span>Despesas</span><strong class="amount-out">${money(expenses)}</strong></div><div><span>Resultado</span><strong class="${balance>=0?"amount-in":"amount-out"}">${money(balance)}</strong></div><div><span>Movimentos</span><strong>${rows.length}</strong></div>`;table.innerHTML=`<thead><tr><th>Data</th><th>Descrição</th><th>Categoria</th><th>Tipo</th><th>Status</th><th>Entrada</th><th>Saída</th></tr></thead><tbody>${rows.length?rows.map(item=>{const amount=parseAmountValue(item.amount);const isOut=transactionIsOut(item);return`<tr><td>${formatDate(item.date)}</td><td>${esc(item.description||"")}</td><td><span class="badge">${esc(item.category||"Sem categoria")}</span></td><td><span class="badge">${isOut?"Despesa":"Faturamento"}</span></td><td><span class="badge">${esc(item.status||"")}${transactionIsOverduePendingOut(item)?" - Vencida":""}</span></td><td>${!isOut?money(amount):"-"}</td><td>${isOut?money(amount):"-"}</td></tr>`}).join(""):`<tr><td colspan="6">${emptyState()}</td></tr>`}</tbody>`}
function bindProfitExpenseReport(){document.querySelector("#generate-profit-expense")?.addEventListener("click",renderProfitExpenseReport);["#profit-expense-start","#profit-expense-end"].forEach(selector=>document.querySelector(selector)?.addEventListener("change",renderProfitExpenseReport));document.querySelector("#export-profit-expense")?.addEventListener("click",()=>exportTableCsv("faturamento-e-despesas.csv",["Data","Descrição","Categoria","Tipo","Status","Entrada","Saída"],profitExpenseRows().map(item=>{const amount=parseAmountValue(item.amount);const isOut=transactionIsOut(item);return[formatDate(item.date),item.description||"",item.category||"Sem categoria",isOut?"Despesa":"Faturamento",item.status||"",!isOut?amount.toFixed(2):"",isOut?amount.toFixed(2):""]})))}
function exportTableCsv(filename,headers,rows){const csv=[headers,...rows].map(row=>row.map(value=>`"${String(value??"").replaceAll('"','""')}"`).join(";")).join("\n");const blob=new Blob(["\ufeff"+csv],{type:"text/csv;charset=utf-8"});const url=URL.createObjectURL(blob);const link=document.createElement("a");link.href=url;link.download=filename;link.click();URL.revokeObjectURL(url)}